// This script removes scripts, styles, and extra whitespace to save tokens
const html = $input.first().json.data;

if (!html) return { text: "No data found" };

const cleanText = html
  .replace(/<script\b[^>]*>([\s\S]*?)<\/script>/gim, "") // Remove Scripts
  .replace(/<style\b[^>]*>([\s\S]*?)<\/style>/gim, "")   // Remove CSS
  .replace(/<[^>]+>/g, " ")                             // Remove all HTML tags
  .replace(/\s+/g, " ")                                 // Collapse extra spaces
  .trim();

// To be even safer, we take the first 15,000 characters 
// (Usually enough for price/offers while staying under limits)
return {
  cleaned_content: cleanText.substring(0, 15000)
};

// Get the raw text string from the Groq output field
const rawText = $json.output;

try {
  // Remove any potential Markdown formatting (like ```json) if present
  const cleanJson = rawText.replace(/```json|```/g, "").trim();

  // Parse the string into a JSON object
  const data = JSON.parse(cleanJson);

  // Return the cleaned data fields
  return {
    product_name: data.product_name,
    current_price: data.current_price,
    current_offer: data.current_offer
  };
} catch (error) {
  // Fallback in case Groq sends a non-JSON response or conversational text
  return {
    error: "Failed to parse Groq output",
    raw_output: rawText
  };
}

const items = $input.all();
let marketData = "COMPREHENSIVE MARKET INTELLIGENCE REPORT:\n\n";

const mainProductName = items[0].json["Product Name"] || "Target Product";

items.forEach((item, index) => {
  const d = item.json;

  const competitor = d["Competitor Name"] || "Unknown Competitor";
  const histPrice = parseFloat(d["Last Known Price"]) || 0;
  const currPrice = parseFloat(d["Current Price"]) || 0;
  const histOffer = d["Last Known Offer"] || "No prior offer data";
  const currOffer = d["Current Offer"] || "No current offer data";

  const priceDiff = currPrice - histPrice;
  const percentChange = histPrice !== 0 ? ((priceDiff / histPrice) * 100).toFixed(2) : 0;

  let movementStatus = "STABLE";
  if (priceDiff < 0) {
    movementStatus = `PRICE DROP detected (Reduced by ₹${Math.abs(priceDiff)} / ${Math.abs(percentChange)}%)`;
  } else if (priceDiff > 0) {
    movementStatus = `PRICE INCREASE detected (Increased by ₹${priceDiff} / ${percentChange}%)`;
  }

  marketData += `COMPETITOR #${index + 1}: ${competitor.toUpperCase()}\n`;
  marketData += `Product Variant: ${d["Product Name"]}\n`;
  marketData += `Current Market Action: ${movementStatus}\n`;
  marketData += `Pricing Breakdown:\n`;
  marketData += `    - Previous Price: ₹${histPrice}\n`;
  marketData += `    - Current Live Price: ₹${currPrice}\n`;
  marketData += `Offer Evolution:\n`;
  marketData += `    - Was: ${histOffer}\n`;
  marketData += `    - Is: ${currOffer}\n`;
  marketData += `Strategic Gap: ${priceDiff < 0 ? "Competitor is aggressively capturing volume." : "Competitor is prioritizing margin over volume."}\n`;
  marketData += `----------------------------------------------------------\n\n`;
});

return [
  {
    json: {
      aggregated_market_data: marketData,
      product_name: mainProductName
    },
    pairedItem: {
      item: 0
    }
  }
];
